import { defineConfig } from 'sanity'
import { structureTool } from 'sanity/structure'
import { visionTool } from '@sanity/vision'
import { vercelDeployTool } from 'sanity-plugin-vercel-deploy'
import { schema, singletonTypes } from './src/sanity/schemaTypes'
import { bulkImportTool } from './src/sanity/tools/BulkImportTool'
export default defineConfig({
    name: 'default',
    title: 'YES Scholarship CMS',

    projectId: process.env.NEXT_PUBLIC_SANITY_PROJECT_ID || 'your-project-id',
    dataset: process.env.NEXT_PUBLIC_SANITY_DATASET || 'production',

    basePath: '/studio',
    apiVersion: '2024-02-03',

    plugins: [
        structureTool({
            structure: (S: any) =>
                S.list()
                    .title('Content Content')
                    .items([
                        // Singleton for Hero
                        S.listItem()
                            .title('Hero Section')
                            .id('hero')
                            .child(
                                S.document()
                                    .schemaType('hero')
                                    .documentId('hero')
                            ),
                        // Singleton for FAQs
                        S.listItem()
                            .title('FAQs Section')
                            .id('faqs')
                            .child(
                                S.document()
                                    .schemaType('faqs')
                                    .documentId('faqs')
                            ),
                        S.divider(),
                        // Regular blog posts
                        S.documentTypeListItem('post').title('Blog Posts'),
                        S.documentTypeListItem('testimonial').title('Testimonials'),
                        S.documentTypeListItem('distribution').title('Sebaran Awardee'),
                        S.documentTypeListItem('ptn').title('Sebaran Alumni PTN'),
                    ]),
        }),
        visionTool(),
        vercelDeployTool(),
    ],
    tools: [bulkImportTool()],

    schema: {
        types: schema.types,
        // Filter out singleton types from the global "New document" menu
        templates: (prev) =>
            prev.filter((template) => !singletonTypes.has(template.schemaType)),
    },

    document: {
        // For singleton types, filter out actions that are not allowed
        actions: (prev, { schemaType }) => {
            if (singletonTypes.has(schemaType)) {
                return prev.filter(({ action }) => action !== 'delete' && action !== 'duplicate' && action !== 'unpublish')
            }
            return prev
        },
    },
})
